import java.util.*;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        long[] ans = new long[queries.length];
        for (int i = 0; i < queries.length; i++) {
            long li = queries[i][0];
            long ri = queries[i][1];
            long threshold = queries[i][2];

            Map<Long, Long> freq = new HashMap<>();
            for (long j = li; j <= ri; j++) {
                long num = nums[(int)j];
                freq.put(num, freq.getOrDefault(num, 0L) + 1);
            }

            List<Map.Entry<Long, Long>> candidates = new ArrayList<>();
            for (Map.Entry<Long, Long> entry : freq.entrySet()) {
                if (entry.getValue() >= threshold) {
                    candidates.add(entry);
                }
            }

            if (candidates.isEmpty()) {
                ans[i] = -1;
            } else {
                candidates.sort((a, b) -> {
                    int cmp = Long.compare(b.getValue(), a.getValue());
                    if (cmp != 0) return cmp;
                    return Long.compare(a.getKey(), b.getKey());
                });
                ans[i] = candidates.get(0).getKey();
            }
        }
        return ans;
    }
}
